impl Solution {
    pub fn sort_list(head: Option<Box<ListNode>>) -> Option<Box<ListNode>> {
        fn merge(l1: Option<Box<ListNode>>, l2: Option<Box<ListNode>>) -> Option<Box<ListNode>> {
            match (l1, l2) {
                (None, None) => None,
                (Some(n), None) | (None, Some(n)) => Some(n),
                (Some(n1), Some(n2)) => {
                    if n1.val <= n2.val {
                        Some(Box::new(ListNode { val: n1.val, next: merge(n1.next, Some(n2)) }))
                    } else {
                        Some(Box::new(ListNode { val: n2.val, next: merge(Some(n1), n2.next) }))
                    }
                }
            }
        }
        fn sort(head: Option<Box<ListNode>>) -> Option<Box<ListNode>> {
            if head.is_none() || head.as_ref().unwrap().next.is_none() { return head; }
            let mut slow = head.as_ref().unwrap();
            let mut fast = slow.next.as_ref().unwrap();
            while fast.next.is_some() {
                slow = slow.next.as_ref().unwrap();
                fast = fast.next.as_ref().unwrap();
                if fast.next.is_some() { fast = fast.next.as_ref().unwrap(); }
            }
            let mid = slow.next.clone();
            let mut node = head;
            node.as_mut().unwrap().next = None;
            let left = sort(node);
            let right = sort(mid);
            merge(left, right)
        }
        sort(head)
    }
}

