use std::collections::BinaryHeap;
use std::cmp::Reverse;
impl Solution {
    pub fn min_meeting_rooms(mut intervals: Vec<Vec<i32>>) -> i32 {
        if intervals.is_empty() { return 0 }
        intervals.sort_by_key(|v| v[0]);
        let mut heap: BinaryHeap<Reverse<i32>> = BinaryHeap::new();
        heap.push(Reverse(intervals[0][1]));
        for i in 1..intervals.len() {
            if let Some(&Reverse(earliest)) = heap.peek() {
                if intervals[i][0] >= earliest { heap.pop(); }
            }
            heap.push(Reverse(intervals[i][1]));
        }
        heap.len() as i32
    }
}

