    freq := map[byte]int{}
    for i := 0; i < len(s); i++ { freq[s[i]]++ }
    type pair struct { ch byte; cnt int }
    pairs := make([]pair, 0, len(freq))
    for ch, cnt := range freq { pairs = append(pairs, pair{ch, cnt}) }
    sort.Slice(pairs, func(i, j int) bool { return pairs[i].cnt > pairs[j].cnt })
    var result []byte
    for _, p := range pairs {
        for i := 0; i < p.cnt; i++ { result = append(result, p.ch) }
    }
    return string(result)
}

