from collections import Counter
class Solution:
    def reorganizeString(self, s: str) -> str:
        count = Counter(s)
        n = len(s)
        max_freq = max(count.values())
        if max_freq > (n + 1) // 2:
            return ""
        sorted_chars = sorted(count.items(), key=lambda x: -x[1])
        result = [''] * n
        i = 0
        for ch, freq in sorted_chars:
            for _ in range(freq):
                result[i] = ch
                i += 2
                if i >= n:
                    i = 1
        return ''.join(result)

