use std::collections::HashMap;
impl Solution {
    pub fn reorganize_string(s: String) -> String {
        let mut freq = [0i32; 26];
        for b in s.bytes() { freq[(b - b'a') as usize] += 1; }
        let (mut max_freq, mut max_char) = (0, 0);
        for i in 0..26 {
            if freq[i] > max_freq { max_freq = freq[i]; max_char = i; }
        }
        if max_freq > ((s.len() as i32 + 1) / 2) { return String::new(); }
        let mut result = vec![b' '; s.len()];
        let mut idx = 0;
        while freq[max_char] > 0 { result[idx] = b'a' + max_char as u8; idx += 2; freq[max_char] -= 1; }
        for i in 0..26 {
            while freq[i] > 0 {
                if idx >= s.len() { idx = 1; }
                result[idx] = b'a' + i as u8; idx += 2; freq[i] -= 1;
            }
        }
        String::from_utf8(result).unwrap()
    }
}

